#include <iostream>
using namespace std;
int main()
{
    int n;
    cin>>n;
    int a[10005],count=0;
    for(int i=0;i<=n-1;i++)
    {
        cin>>a[i];
    }
    for(int i=1;i<=n-1;i++)
    {
        for(int j=0;j<=n-i-1;j++)
        {
            if(a[j+1]<a[j])
            {
                count+=1;
                swap(a[j+1],a[j]);
            }
        }
    }
    cout<<count<<endl;
    return 0;
}
